refsection.programlisting:
// load the database containing the GDP for 25 countries in the OECD over the period 1963-2003
load(GROCERDIR+'/data/gdpan_oecd.dat');
// retrieve the names of all variables in database
listvar=dblist(GROCERDIR+'/macros/grocer/db/gdpan_oecd.dat')
res =  Chang_IV('log('+listvar+')','pmax=4','t_order=0')
// Example taken from function Chang_IV_d(): provides the Chang test for all variables in the database, taken in logarithm,
// with a constant but not trend ('t_order=0'), the Lag order  set to 4 (arg 'pmax=4'),
// the function F(x)=x*exp(-ci*|x|) used as an instrument generating function and a 5% significance level (default values).

res = Chang_IV('log('+listvar+')','lagorders=4*ones(size(listvar,1),1)','t_order=0','signif=0.01','IGF=2')
// Provides now the Chang test for all variables in the database, taken in logarithm,
// with a constant but not trend ('t_order=0'), the Lag order to be determined by the program,
// the maximum number of lags set to 4 (arg 'lagorders=4*ones(size(listvar,1),1)'),
// the function F(x)=I(|x|%lt;K) used as an instrument generating function and a 10% significance level.
